// Devuelve UN ITEM POR CADA adjunto (PDF o imagen) encontrado en el email
function findAllAttachments(parts, depth) {
  if (!Array.isArray(parts) || depth > 10) return [];
  let attachments = [];
  for (const part of parts) {
    const mime = (part.mimeType || '').toLowerCase();
    const filename = (part.filename || '');
    const filenameLower = filename.toLowerCase();
    const hasAttach = !!(part.body && part.body.attachmentId);
    const size = (part.body && part.body.size) || 0;

    if (hasAttach && size > 0) {
      const isPdf   = mime.includes('pdf')  || filenameLower.endsWith('.pdf');
      const isImage = mime.includes('image') ||
                      filenameLower.endsWith('.jpg')  ||
                      filenameLower.endsWith('.jpeg') ||
                      filenameLower.endsWith('.png');

      if (isPdf || isImage) {
        const fileType = isPdf ? 'pdf' : 'image';
        attachments.push({
          attachmentId: part.body.attachmentId,
          filename:     filename || (isPdf ? 'factura.pdf' : 'factura.jpg'),
          fileType:     fileType,
          mimeType:     mime
        });
      }
    }

    if (part.parts) {
      attachments = attachments.concat(findAllAttachments(part.parts, depth + 1));
    }
  }
  return attachments;
}

const payload = $json.payload || {};
const headers = (payload.headers || []).reduce((a, h) => ({ ...a, [h.name.toLowerCase()]: h.value }), {});

const emailMeta = {
  email_gmail_id:  $json.id,
  email_from:      headers.from    || '',
  email_subject:   headers.subject || '',
  email_date:      $json.internalDate || new Date().toISOString(),
  email_messageId: $json.id
};

const attachments = findAllAttachments(payload.parts || [], 0);

if (attachments.length === 0) {
  const tree = JSON.stringify((payload.parts || []).map(function m(p) {
    return { mime: p.mimeType, file: p.filename || '', hasId: !!(p.body && p.body.attachmentId), sub: (p.parts || []).map(m) };
  }));
  throw new Error('Sin adjuntos PDF o imagen encontrados. Arbol: ' + tree);
}

return attachments.map(att => ({
  json: {
    messageId:    $json.id,
    attachmentId: att.attachmentId,
    pdf_filename: att.filename,
    file_type:    att.fileType,
    mime_type:    att.mimeType,
    ...emailMeta
  }
}));

// Convierte base64url de Gmail API a $binary
// Detecta si es PDF o imagen y setea el mimeType correcto
const meta = $('Extraer metadata adjunto').item.json;
const base64url = $json.data || '';

if (!base64url) throw new Error('Gmail API no devolvio datos del adjunto');

const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
const buffer = Buffer.from(base64, 'base64');

// Determinar mimeType real
const isPdf = meta.file_type === 'pdf';
const mimeType = isPdf
  ? 'application/pdf'
  : (meta.mime_type || 'image/jpeg');

const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  meta.pdf_filename,
  mimeType
);

return [{
  json: {
    pdf_binary_key:  'data',
    pdf_filename:    meta.pdf_filename,
    file_type:       meta.file_type,
    mime_type:       mimeType,
    base64_data:     base64,          // guardamos base64 limpio para Vision si es imagen
    email_gmail_id:  meta.email_gmail_id,
    email_from:      meta.email_from,
    email_subject:   meta.email_subject,
    email_date:      meta.email_date,
    email_messageId: meta.email_messageId
  },
  binary: { data: binaryData }
}];

// Normaliza salida de extractFromFile (PDF) al mismo formato que Vision
