// Normaliza salida de OpenAI Vision al mismo formato que extractFromFile
const src = $('Preparar binario').item.json;
const choice = ($json.choices || [])[0] || {};
const rawText = (choice.message && choice.message.content) || '';

if (!rawText) throw new Error('Vision no devolvio texto de la imagen');

return [{ json: {
  pdf_text:        rawText,
  pdf_filename:    src.pdf_filename,
  file_type:       'image',
  email_gmail_id:  src.email_gmail_id,
  email_from:      src.email_from,
  email_subject:   src.email_subject,
  email_date:      src.email_date,
  email_messageId: src.email_messageId
}}];

// Genera hash del texto y arma payload unificado (PDF + imagen convergen aquí)
const rawText = $json.pdf_text || '';

let hash;
try {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(rawText));
  hash = Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
} catch(e) {
  let h = 5381;
  for (let i = 0; i < rawText.length; i++) h = (((h << 5) + h) + rawText.charCodeAt(i)) & 0xffffffff;
  hash = (h >>> 0).toString(16).padStart(8, '0') + rawText.length.toString(16);
}

return [{ json: {
  pdf_text:        rawText,
  pdf_filename:    $json.pdf_filename,
  file_type:       $json.file_type,
  pdf_hash:        hash,
  email_gmail_id:  $json.email_gmail_id,
  email_from:      $json.email_from,
  email_subject:   $json.email_subject,
  email_date:      $json.email_date,
  email_messageId: $json.email_messageId,
  fuente:          'EMAIL_GMAIL_N8N'
}}];

// -- NODO: Normalizar campos OpenAI -> staging_facturas --
const prevNode = $('Preparar prompt OpenAI').item.json;

let rawContent = '';
if (typeof $json.output === 'string' && $json.output.trim().startsWith('{')) {
  rawContent = $json.output;
} else if ($json.message && $json.message.content) {
  rawContent = $json.message.content;
} else if ($json.choices && $json.choices[0] && $json.choices[0].message) {
  rawContent = $json.choices[0].message.content;
} else if (typeof $json.output === 'string') {
  rawContent = $json.output;
} else if (typeof $json.content === 'string') {
  rawContent = $json.content;
} else {
  rawContent = JSON.stringify($json);
}

let parsed;
try {
  const clean = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  const m = rawContent.match(/\{[\s\S]+\}/);
  if (m) {
    try { parsed = JSON.parse(m[0]); } catch(e2) {
      throw new Error('No se pudo parsear JSON de OpenAI: ' + e.message + ' | Raw: ' + rawContent.substring(0, 500));
    }
  } else {
    throw new Error('Respuesta OpenAI no contiene JSON valido: ' + rawContent.substring(0, 300));
  }
}

function parseDate(d) {
  if (!d) return null;
  const s = String(d).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const a = s.match(/^(\d{2})[\/\-](\d{2})[\/\-](\d{4})$/);
  if (a) return `${a[3]}-${a[2]}-${a[1]}`;
  const b = s.match(/^(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
  if (b) return `${b[1]}-${b[2]}-${b[3]}`;
  return null;
}

const esc = s => s ? String(s).replace(/'/g, "''") : null;
const str = (s, nullable = true) => (s !== null && s !== undefined && s !== '') ? `'${esc(s)}'` : (nullable ? 'NULL' : "''");
const numF = n => (n !== null && n !== undefined && !isNaN(n)) ? parseFloat(n) : 0;

const letra         = parsed.letra || 'A';
const tipo_operacion = (() => {
  const tc = (parsed.tipo_comprobante || '').toUpperCase();
  if (tc.includes('NC') || tc.includes('CREDITO')) return 'NC_COMPRA';
  if (tc.includes('ND') || tc.includes('DEBITO'))  return 'ND_COMPRA';
  return 'FACTURA_COMPRA';
})();

const nro_documento     = parsed.numero_completo    || null;
const fecha_emision     = parseDate(parsed.fecha_emision);
const fecha_vto_cae     = parseDate(parsed.fecha_vto_cae);
const fecha_vencimiento = parseDate(parsed.fecha_vencimiento);
const cuit              = parsed.emisor_cuit         || null;
const cuit_receptor     = parsed.receptor_cuit       || null;
const razon_social      = parsed.emisor_razon_social || null;
const moneda            = parsed.moneda || 'ARS';
const es_dolar          = (moneda === 'USD') ? 1 : 0;
const cotizacion_usd    = parsed.cotizacion_usd      || null;
const cotizacion_origen = es_dolar ? (cotizacion_usd ? 'FACTURA' : 'BNA_PENDIENTE') : 'PESOS';
const neto              = numF(parsed.neto_gravado);
const iva_21            = numF(parsed.iva_21);
const iva_105           = numF(parsed.iva_105);
const percepciones      = numF(parsed.percepciones);
const otros_impuestos   = numF(parsed.otros_impuestos);
const total             = numF(parsed.total);
const cae               = parsed.cae       || null;
const referencia        = parsed.referencia || null;
const nro_remito        = parsed.nro_remito || null;

const confianza_label = parsed.confianza_parseo || 'MEDIA';
const confianza_num   = confianza_label === 'ALTA' ? 100 : (confianza_label === 'MEDIA' ? 70 : 30);

const items      = Array.isArray(parsed.items) ? parsed.items : [];
const items_json = JSON.stringify(items);

const staging_id = (() => {
  try { return crypto.randomUUID(); } catch(e) {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
      const r = Math.random() * 16 | 0;
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
  }
})();

const monedaId       = es_dolar ? '76C69768-3DAE-11D5-B059-004854841C8A' : '76C69765-3DAE-11D5-B059-004854841C8A';
const cotizacion_val = cotizacion_usd || 1;

const sql_query = `INSERT INTO UD_EZI_STAGING_FACTURAS (
  id, tipo_operacion, estado_proceso, fecha_carga, usuario_carga, origen,
  tipotransaccion_id, numerodocumento, letra, fecha_emision, fecha_vencimiento,
  proveedor_id, proveedor_codigo, proveedor_cuit, proveedor_nombre,
  neto, iva_21, iva_105, percepciones, otros_impuestos, total,
  moneda_id, cotizacion, cae, fecha_vto_cae, compania_id,
  pdf_filename, pdf_hash, email_origen, email_asunto, items_json,
  referencia, nro_remito,
  es_dolar, cotizacion_origen, cotizacion_aviso
) VALUES (
  '${esc(staging_id)}','${esc(tipo_operacion)}','PENDIENTE',CONVERT(varchar(8), GETDATE(), 112) + REPLACE(REPLACE(REPLACE(CONVERT(varchar(12), GETDATE(), 114),':',''),'.',''),' ',''),'n8n-openai','PDF_EMAIL',
  '50829758-5905-11D5-86C4-0080AD403F5F',
  ${str(nro_documento)},${str(letra)},${str(fecha_emision)},${str(fecha_vencimiento)},
  '00000000-0000-0000-0000-000000000000','PENDIENTE',
  ${str(cuit)},${str(razon_social)},
  ${numF(neto)},${numF(iva_21)},${numF(iva_105)},${numF(percepciones)},${numF(otros_impuestos)},${numF(total)},
  '${monedaId}',${cotizacion_val},
  ${str(cae)},${str(fecha_vto_cae)},
  'FC20C32D-3EFA-11D5-86AD-0080AD403F5F',
  ${str(prevNode.pdf_filename)},${str(prevNode.pdf_hash)},${str(prevNode.email_from)},${str(prevNode.email_subject)},${str(items_json)},
  ${str(referencia)},${str(nro_remito)},
  ${es_dolar || 0},${str(cotizacion_origen)},NULL
)`;

return [{ json: {
  staging_id,
  tipo_operacion,
  cuit,
  cuit_receptor,
  razon_social,
  letra,
  nro_documento,
  fecha_emision,
  fecha_vencimiento,
  fecha_vto_cae,
  cae,
  neto,
  iva_21,
  iva_105,
  percepciones,
  otros_impuestos,
  total,
  es_dolar,
  cotizacion_usd,
  cotizacion_val,
  cotizacion_origen,
  referencia,
  nro_remito,
  items_json,
  items_count:            items.length,
  confianza_parseo:       confianza_num,
  confianza_parseo_label: confianza_label,
  notas_parseo:           parsed.notas_parseo || null,
  sql_query,
  pdf_filename:    prevNode.pdf_filename,
  file_type:       prevNode.file_type,
  pdf_hash:        prevNode.pdf_hash,
  email_from:      prevNode.email_from,
  email_subject:   prevNode.email_subject,
  email_date:      prevNode.email_date,
  email_gmail_id:  prevNode.email_gmail_id,
  fuente:          prevNode.fuente || 'EMAIL_GMAIL_N8N',
  pdf_text:        prevNode.pdf_text,
  openai_raw:      rawContent.substring(0, 500)
}}];

const invoice = $('¿Necesita cotización BNA?').item.json;
const bcraResp = $input.first().json;

function parseDate(d) {
  if (!d) return null;
  const s = String(d).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const a = s.match(/^(\d{2})[\/\-](\d{2})[\/\-](\d{4})$/);
  if (a) return `${a[3]}-${a[2]}-${a[1]}`;
  const b = s.match(/^(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
  if (b) return `${b[1]}-${b[2]}-${b[3]}`;
  return null;
}

const results = bcraResp.results || [];
let cotizacion_usd    = null;
let cotizacion_origen = 'PESOS';
let cotizacion_aviso  = null;

if (results.length > 0) {
  cotizacion_usd    = results[0].valor;
  cotizacion_origen = 'BNA';
  cotizacion_aviso  = 'Cotizacion no encontrada en la factura. TC BNA del ' + results[0].fecha + ': $ ' + cotizacion_usd + ' por USD. Verificar con el proveedor.';
} else {
  cotizacion_origen = 'PESOS';
  cotizacion_aviso  = 'No se encontro cotizacion en la factura ni en BNA para la fecha ' + invoice.fecha_emision + '. Verificar manualmente.';
}

const esc = s => s ? String(s).replace(/'/g, "''") : null;
const str = (s, nullable = true) => (s !== null && s !== undefined && s !== '') ? `'${esc(s)}'` : (nullable ? 'NULL' : "''");
const numF = n => (n !== null && n !== undefined && !isNaN(n)) ? parseFloat(n) : 0;

const j = Object.assign({}, invoice, { cotizacion_usd, cotizacion_origen, cotizacion_aviso });
const confianza_label = j.confianza_parseo_label || (j.confianza_parseo >= 80 ? 'ALTA' : j.confianza_parseo >= 50 ? 'MEDIA' : 'BAJA');
const monedaId        = j.es_dolar ? '76C69768-3DAE-11D5-B059-004854841C8A' : '76C69765-3DAE-11D5-B059-004854841C8A';
const cotizacion_val  = cotizacion_usd || 1;

const sql_query = `INSERT INTO UD_EZI_STAGING_FACTURAS (
  id, tipo_operacion, estado_proceso, fecha_carga, usuario_carga, origen,
  tipotransaccion_id, numerodocumento, letra, fecha_emision, fecha_vencimiento,
  proveedor_id, proveedor_codigo, proveedor_cuit, proveedor_nombre,
  neto, iva_21, iva_105, percepciones, otros_impuestos, total,
  moneda_id, cotizacion, cae, fecha_vto_cae, compania_id,
  pdf_filename, pdf_hash, email_origen, email_asunto, items_json,
  referencia, nro_remito,
  es_dolar, cotizacion_origen, cotizacion_aviso
) VALUES (
  '${esc(j.staging_id)}','${esc(j.tipo_operacion)}','PENDIENTE',CONVERT(varchar(8), GETDATE(), 112) + REPLACE(REPLACE(REPLACE(CONVERT(varchar(12), GETDATE(), 114),':',''),'.',''),' ',''),'n8n-openai','PDF_EMAIL',
  '50829758-5905-11D5-86C4-0080AD403F5F',
  ${str(j.nro_documento)},${str(j.letra)},${str(j.fecha_emision)},${str(j.fecha_vencimiento)},
  '00000000-0000-0000-0000-000000000000','PENDIENTE',
  ${str(j.cuit)},${str(j.razon_social)},
