  '${monedaId}',${cotizacion_val},
  ${str(j.cae)},${str(j.fecha_vto_cae)},
  'FC20C32D-3EFA-11D5-86AD-0080AD403F5F',
  ${str(j.pdf_filename)},${str(j.pdf_hash)},${str(j.email_from)},${str(j.email_subject)},${str(j.items_json)},
  ${str(j.referencia)},${str(j.nro_remito)},
  ${j.es_dolar || 0},${str(cotizacion_origen)},${str(cotizacion_aviso)}
)`;

return [{ json: Object.assign({}, j, { sql_query, cotizacion_val }) }];

// Extrae solo los 13 campos que Node-RED necesita
