  json: {
    staging_id:       src.staging_id,
    sql_query:        src.sql_query,
    cuit:             src.cuit,
    razon_social:     src.razon_social,
    nro_documento:    src.nro_documento,
    letra:            src.letra,
    fecha_emision:    src.fecha_emision,
    total:            src.total,
    tipo_operacion:   src.tipo_operacion,
    confianza_parseo: src.confianza_parseo,
